  for (let i = 0; i < 40; i++) {
    confetti.push({
      x: Math.random() * 100,
      delay: Math.random() * 5,
      speed: Math.random() * 3,
      color: confettiColors[i % confettiColors.length],
      size: 4 + Math.random() * 8,
    })
  }
}

// ===== 星空粒子 =====
const starCanvas = ref(null)
let starAnimId = null

class Star {
  constructor(w, h) {
    this.reset(w, h)
  }
  reset(w, h) {
    this.x = Math.random() * w
    this.y = Math.random() * h
    this.size = 1 + Math.random() * 2
    this.speed = 0.2 + Math.random() * 0.5
    this.alpha = 0.3 + Math.random() * 0.7
    this.twinkleSpeed = 0.01 + Math.random() * 0.03
    this.twinklePhase = Math.random() * Math.PI * 2
  }
}

let stars = []
function initStars() {
  const canvas = starCanvas.value
  if (!canvas) return
  canvas.width = window.innerWidth
  canvas.height = window.innerHeight
  const count = Math.floor((canvas.width * canvas.height) / 3000)
  stars = Array.from({ length: count }, () => new Star(canvas.width, canvas.height))
}

function drawStars(time) {
  const canvas = starCanvas.value
  if (!canvas) return
  const ctx = canvas.getContext('2d')
  ctx.clearRect(0, 0, canvas.width, canvas.height)

  for (const star of stars) {
    const alpha = star.alpha * (0.5 + 0.5 * Math.sin(time * star.twinkleSpeed + star.twinklePhase))
    ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`
    ctx.fillRect(Math.floor(star.x), Math.floor(star.y), star.size, star.size)
  }

  starAnimId = requestAnimationFrame(drawStars)
}

// ===== 烟花 =====
const fireworks = reactive([])
let fireworkId = null

function triggerFireworks() {
  const canvas = starCanvas.value
  if (!canvas) return
  const cx = canvas.width / 2
  const cy = canvas.height / 3

  for (let burst = 0; burst < 3; burst++) {
    setTimeout(() => {
      const colors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff9ff3', '#f368e0']
      const color = colors[Math.floor(Math.random() * colors.length)]
      for (let i = 0; i < 24; i++) {
        const angle = (i / 24) * Math.PI * 2
        const speed = 40 + Math.random() * 60
        fireworks.push({
          x: cx + (burst - 1) * 100,
          y: cy + (burst - 1) * 50,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          color,
          life: 1,
          size: 3 + Math.random() * 3,
        })
      }
    }, burst * 400)
  }

  if (!fireworkId) {
    animateFireworks()
  }
}

function animateFireworks() {
  const canvas = starCanvas.value
  if (!canvas) return
  const ctx = canvas.getContext('2d')

  for (let i = fireworks.length - 1; i >= 0; i--) {
    const f = fireworks[i]
    f.x += f.vx * 0.016
    f.y += f.vy * 0.016
    f.vy += 60 * 0.016
    f.life -= 0.02
    f.size *= 0.995

    if (f.life <= 0 || f.size < 0.5) {
      fireworks.splice(i, 1)
    }
  }

  if (fireworks.length > 0) {
    fireworkId = requestAnimationFrame(animateFireworks)
  } else {
    fireworkId = null
  }
}

// ===== 8-bit 像素音乐 (自动循环) =====
const pixelMusicOn = ref(false)
let pixelAudioCtx = null
let pixelMusicInterval = null

function getPixelAudioCtx() {
  if (!pixelAudioCtx) {
    pixelAudioCtx = new (window.AudioContext || window.webkitAudioContext)()
  }
  return pixelAudioCtx
}

function playPixelNote(freq, duration) {
  try {
    const ctx = getPixelAudioCtx()
    const osc = ctx.createOscillator()
    const gain = ctx.createGain()
    osc.connect(gain)
    gain.connect(ctx.destination)
    osc.type = 'square'
    osc.frequency.value = freq
    gain.gain.setValueAtTime(0.07, ctx.currentTime)
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration)
    osc.start()
    osc.stop(ctx.currentTime + duration + 0.05)
  } catch (e) { /* no audio */ }
}

