class BingParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.in_h2 = False
        self.in_a = False
        self.in_p = False
        self.results = []
        self.current = {}
        self.capture = ''
        self.tag_stack = []

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        if tag == 'h2':
            self.in_h2 = True
        if tag == 'a' and self.in_h2:
            self.in_a = True
            self.capture = ''
        if tag == 'p':
            # 检查是否在搜索结果中
            self.in_p = True
            self.capture = ''
        self.tag_stack.append(tag)

    def handle_data(self, data):
        if self.in_a:
            self.capture += data
        elif self.in_p:
            self.capture += data

    def handle_endtag(self, tag):
        if tag == 'a' and self.in_a:
            if self.capture.strip():
                self.current['title'] = self.capture.strip()
            self.in_a = False
        if tag == 'h2':
            self.in_h2 = False
        if tag == 'p' and self.in_p:
            if self.capture.strip():
                if 'title' in self.current and 'snippet' not in self.current:
                    self.current['snippet'] = self.capture.strip()
                    self.results.append(self.current)
                    self.current = {}
            self.in_p = False

